(()=>{"use strict";(new class{constructor(){}addWidget(){document.body.insertAdjacentHTML("beforeend",'\n            <div class="container-widget">\n                <button class="container-widget__btn" type="button">Collapse</button>\n                <div class="container-widget__text-box">\n                    <span class="text">Когда мы придумаем текст тут будет текст, но пока мы его не придумали, так что текста нет. Но обязательно придумаем</span>\n                </div>\n            </div>'),this.animationWidget()}animationWidget(){document.body.addEventListener("click",function(t){t.target.classList.contains("container-widget__btn")&&!t.target.nextElementSibling.classList.contains("activate")?(t.target.nextElementSibling.classList.add("activate"),t.target.nextElementSibling.firstElementChild.classList.add("text-activate"),setTimeout(()=>{t.target.nextElementSibling.style.animationPlayState="paused"},1500)):(t.target.nextElementSibling.style.animationPlayState="running",setTimeout(()=>{t.target.nextElementSibling.classList.remove("activate"),t.target.nextElementSibling.firstElementChild.classList.remove("text-activate")},1500))})}}).addWidget()})();